-- guide_places body(structured, ASCII-safe \u escapes) + price. Re-run safe.
alter table guide_places add column if not exists price text;

update guide_places set body=E'A stylish Japanese restaurant located on the 33rd floor with panoramic views over the sea, mountains, and Batumi skyline. JAPAN 33 combines authentic Japanese cuisine, signature cocktails, sake, and a refined modern atmosphere that feels very different from typical sushi places in the city.\n\nThe restaurant was created as a collaboration between Panorama Restaurant, ORBI Group, and Ginza Project, with chef Ri focusing on authentic Japanese dishes and high-quality natural ingredients. The interior combines natural wood, plants, soft lighting, and Japanese-inspired aesthetics, while evening DJ sets and sunset views make the place especially atmospheric.\n\nPerfect for:\n\n* sushi & sashimi\n* sunset dinners\n* cocktails & sake\n* date nights\n* stylish evening atmosphere\n\nWhat to try:\n\n* sashimi & nigiri\n* signature rolls\n* kaisen don\n* Japanese cocktails\n* sake selection\n\n15b Sherif Khimshiashvili St, 33rd floor, Batumi\n\nSun\u2013Fri: 15:00 \u2013 00:00\n\nSat: 15:00 \u2013 01:00' where slug='japan-33';
update guide_places set body=E'A modern specialty coffee spot in Batumi known for its aesthetic interior, strong breakfast menu, and relaxed European caf\u00e9 atmosphere. Milevskii combines quality coffee, fresh bakery, all-day breakfasts, and cocktails in a space that feels stylish but still cozy and comfortable.\n\nThe place is especially loved for its beautifully presented brunch dishes, syrniki, Benedicts, specialty coffee, and calm atmosphere that works equally well for slow mornings, remote work, or meeting friends. They also have cocktails and wine for later in the day, making it feel more like an all-day coffee bar than a classic caf\u00e9.\n\nPerfect for:\n\n* specialty coffee\n* breakfast & brunch\n* desserts & bakery\n* working remotely\n* relaxed meetings\n\nWhat to try:\n\n* syrniki\n* salmon Benedict\n* flat white\n* filter coffee\n* pastries & desserts\n\n6 Irakli Abashidze St, Batumi\n\nDaily: 09:00 \u2013 20:00' where slug='milevskii-coffee';
update guide_places set price=E'\u224820\u201330 \u20be' where slug='milevskii-coffee';
update guide_places set body=E'One of Batumi\u2019s strongest specialty coffee spots, combining high-quality coffee, a modern minimalist interior, and a full brunch-style menu. Nova feels more like a contemporary European caf\u00e9 than a typical coffee shop, which is why it became a favorite among locals, expats, and people working remotely in the city.\n\nThe place is especially loved for its filter coffee, signature drinks, beautifully presented food, and relaxed atmosphere with good music and plenty of space to work or meet friends. They also have a coffee store with beans and accessories for home brewing.\n\nPerfect for:\n\n* specialty coffee\n* breakfast & brunch\n* working remotely\n* slow mornings\n* meeting friends\n\nWhat to try:\n\n* V60 & filter coffee\n* espresso tonic\n* flat white\n* breakfast dishes\n* tiramisu & desserts\n\n60 Parnavaz Mepe St, Batumi\n\nDaily: 08:00 \u2013 23:00' where slug='nova-coffee';
update guide_places set body=E'LIVI \u2014 BatumiA cozy modern caf\u00e9 built around specialty coffee, fresh pastries, desserts, and relaxed everyday atmosphere. LIVI has quickly become one of the favorite local spots in Batumi for breakfasts, coffee meetings, and slow mornings with good food and beautifully made drinks.' where slug='livi-coffee';
update guide_places set price=E'\u224810\u201320 \u20be' where slug='livi-coffee';
update guide_places set body=E'A stylish restaurant in Gonio combining European cuisine with Georgian influences, cocktails, wine, and a relaxed coastal atmosphere. Located a short drive from Batumi, ELLY feels more like a hidden seaside escape than a typical tourist restaurant.\n\nThe space is especially loved for its terrace, slow dinners, breakfast by the sea, and calm aesthetic atmosphere surrounded by greenery and the quieter side of the coast. A perfect place for escaping the busy city for a few hours.\n\nPerfect for:\n\n* breakfast & brunch\n* sunset dinners\n* wine & cocktails\n* slow weekends outside Batumi\n* relaxed evenings by the sea\n\nWhat to try:\n\n* European dishes with Georgian accents\n* cocktails & wine\n* seafood\n* breakfast menu\n* desserts\n\nGonio, 18 Andria Pirveltsodebuli Hwy III Deadlock\n\nDaily: 09:00 \u2013 21:00' where slug='elly-restaurant-gonio';
update guide_places set price=E'\u224830\u201370 \u20be' where slug='elly-restaurant-gonio';
update guide_places set body=E'A beautiful caf\u00e9 and restaurant located near the Batumi Botanical Garden, surrounded by greenery, sea views, and a calm resort atmosphere. Botanico feels more like a hidden coastal escape than a typical city restaurant \u2014 perfect for slow lunches, sunset dinners, and long conversations with wine.\n\nThe place combines Georgian and European cuisine with a stylish modern aesthetic, poolside atmosphere, cocktails, and panoramic views of the Black Sea. One of the best spots around Batumi for a relaxed dinner outside the busy city center.\n\nPerfect for:\n\n* sunset dinners\n* wine & cocktails\n* food with a sea view\n* slow weekends outside the city\n* special occasions\n\nWhat to try:\n\n* Georgian & European dishes\n* seafood\n* cocktails\n* wine selection\n* desserts\n\nGreen Cape, near Batumi Botanical Garden\nLocation\nDaily: 12:00 \u2013 00:00' where slug='botanico-cafe';
update guide_places set body=E'AlcoBrand \u2014 BatumiOne of the most popular alcohol stores in Batumi with a large selection of Georgian and imported wines, whiskey, gin, tequila, beer, and premium spirits. A great place if you want something beyond the typical supermarket selection.' where slug='alcobrand';
update guide_places set body=E'Gastronom \u2014 BatumiA stylish gourmet grocery and delicatessen store with a carefully selected collection of European products, wine, cheese, snacks, desserts, and specialty food items that are hard to find elsewhere in Batumi.' where slug='gastronome-batumi';
update guide_places set body=E'8000 Vintages \u2014 BatumiOne of the best places in Batumi to discover Georgian wine culture. 8000 Vintages is a modern wine shop and bar focused on carefully selected wines from small Georgian wineries, including natural and qvevri wines from different regions of the country.' where slug='8000-vintages';
update guide_places set body=E'A unique natural wine bar and wine shop located inside a former family garage in Old Batumi. Garage Wines is one of the most atmospheric places in the city for discovering Georgian natural, organic, and biodynamic wines in a relaxed and authentic setting.\n\nThe place feels more like a hidden local gathering spot than a traditional wine bar \u2014 with vintage interiors, wine cellars, candlelight atmosphere, cheese, conversations, and a team that genuinely loves wine culture. Many guests come here not only to drink wine, but to learn more about Georgian winemaking and try small producers you rarely find elsewhere.\n\nPerfect for:\n\n* natural Georgian wines\n* wine & cheese evenings\n* authentic local atmosphere\n* date nights\n* slow conversations and late evenings\n\nWhat to try:\n\n* natural qvevri wines\n* cheese plates\n* Georgian biodynamic wines\n* homemade desserts\n* local tea & chacha\n\n8 Giorgi Mazniashvili St, Batumi\n\nDaily: 18:00 \u2013 01:00\n\nFriday\u2013Saturday: until 02:00' where slug='garage-wines-wine-bar';
update guide_places set price=E'\u224810\u201340 \u20be' where slug='garage-wines-wine-bar';
update guide_places set body=E'A small but very atmospheric cocktail bar in Batumi known for its strong cocktail culture, friendly bartenders, and relaxed late-night vibe. Qube feels more like a hidden local spot than a tourist bar \u2014 the kind of place people return to for conversations, music, and really well-made drinks.\n\nThe bar is especially loved for its classic and signature cocktails, cozy interior, and welcoming atmosphere without unnecessary glamour or loud club energy. Perfect both for starting the night and for staying until late.\n\nPerfect for:\n\n* cocktails & nightlife\n* late-night drinks\n* relaxed atmosphere\n* meeting friends\n* starting the night in Batumi\n\nWhat to try:\n\n* signature cocktails\n* Negroni\n* Daiquiri\n* Espresso Martini\n* custom cocktails based on your taste\n\n4 Sherif Khimshiashvili St, Batumi\n\nDaily: 20:00 \u2013 05:00' where slug='qube-bar';
update guide_places set price=E'\u224820\u201370 \u20be' where slug='qube-bar';
update guide_places set body=E'Gimlet \u2014 BatumiOne of Batumi\u2019s best cocktail bars for people who appreciate classic drinks, good music, and a stylish but relaxed atmosphere. Gimlet combines modern bar culture with a cozy European vibe, making it a perfect place for both quiet evening cocktails and starting a longer night out.' where slug='gimlet-bar';
update guide_places set price=E'\u224820\u201360 \u20be' where slug='gimlet-bar';
update guide_places set body=E'An elegant modern Georgian restaurant located inside the Radisson Blu Hotel, combining traditional Georgian flavors with a more refined contemporary style. Medea is one of the best places in Batumi for a stylish dinner, wine, and a calmer upscale atmosphere away from the typical tourist restaurants.\n\nThe interior feels modern and sophisticated, while the menu mixes classic Georgian dishes with European presentation and fine dining touches. In summer, the terrace becomes one of the nicest spots for long dinners and evening wine.\n\nPerfect for:\n\n* elegant dinners\n* Georgian cuisine with a modern twist\n* wine & cocktails\n* date nights\n* business meetings\n\nWhat to try:\n\n* Adjarian khachapuri\n* khinkali\n* grilled meat dishes\n* Georgian wine\n* desserts\n\nNinoshvili St. 1, Radisson Blu Hotel, Batumi\n\nDaily: 13:00 \u2013 00:00' where slug='medea-restaurant';
update guide_places set body=E'Brasserie 1900 \u2014 BatumiA beautiful European-style brasserie in the heart of Old Batumi with elegant interiors, classic atmosphere, and one of the most refined dining experiences in the city. Inspired by traditional French and European brasseries, the place combines timeless design, wine culture, and carefully prepared dishes.' where slug='brasserie-1900';
update guide_places set body=E'A quiet aesthetic caf\u00e9 in Batumi built around specialty coffee, signature breakfasts, and a warm, relaxed atmosphere. Moonrise combines minimalist design, soft natural light, and carefully curated details that make it feel more like a calm creative space than a typical caf\u00e9.\n\nThe place is especially loved for slow mornings, brunches, beautiful presentation, and a cozy atmosphere equally good for conversations, working remotely, or simply taking a break from the city.\n\nPerfect for:\n\n* specialty coffee\n* signature breakfasts\n* brunch & desserts\n* working remotely\n* slow mornings\n\nWhat to try:\n\n* breakfast dishes\n* specialty coffee\n* desserts\n* signature drinks\n\nDavid Mamuladze 19, Batumi\n\nDaily: 09:00 \u2013 23:00' where slug='moonrise';
update guide_places set body=E'RAVI \u2014 BatumiA stylish all-day caf\u00e9 with a modern interior, trendy drinks, and a relaxed atmosphere that makes you want to stay longer than planned. RAVI combines comfort, good food, music, and an aesthetic vibe that feels fresh and modern without trying too hard.' where slug='ravi-neobistro';
update guide_places set price=E'\u224820\u201350 \u20be' where slug='ravi-neobistro';
update guide_places set body=E'Coffee, Bakery & Food \u2014 BatumiOne of Batumi\u2019s cozy everyday spots for good coffee, fresh pastries, and relaxed breakfasts. Open since 2019, this place has built a loyal local following thanks to its warm atmosphere, quality bakery, and simple but consistently good food.' where slug='rhino-coffee';
update guide_places set body=E'Minimalist \u2014 BatumiA calm and beautifully designed caf\u00e9 where simplicity, good coffee, and relaxed atmosphere come together. Minimalist has quickly become one of Batumi\u2019s favorite spots for specialty coffee, slow breakfasts, and quiet mornings away from the busy tourist streets.' where slug='minimalist-coffee-and-food';
update guide_places set body=E'Specialty Coffee Bar & European FoodA cozy modern caf\u00e9 combining specialty coffee, European comfort food, and a relaxed neighborhood atmosphere. One of those places in Batumi that works equally well for breakfast, lunch, coffee with a laptop, or a slow evening with wine and friends.' where slug='nord-specialty-coffee-food';
update guide_places set price=E'\u224810\u201320 \u20be' where slug='nord-specialty-coffee-food';
update guide_places set body=E'Nord Specialty Coffee \u2014 BatumiOne of the most loved specialty coffee spots in Batumi, known for its minimalist Scandinavian-style interior, excellent coffee, and calm atmosphere. A perfect place for slow mornings, working from a laptop, or taking a break from the city.' where slug='nord-coffee-old-town';
update guide_places set body=E'Pure Bistro \u2014 BatumiA stylish modern bistro from the creators of one of Batumi\u2019s favorite specialty coffee spots \u2014 but in a completely new format. Pure Bistro combines beautiful interior design, warm natural light, wine, cocktails, and a relaxed European atmosphere made for long brunches and slow dinners with friends.' where slug='pure-bistro';
update guide_places set price=E'\u224820\u201330 \u20be' where slug='pure-bistro';
update guide_places set body=E'Nisha \u2014 BatumiA stylish all-day caf\u00e9 and bar with a relaxed atmosphere, good music, cocktails, and one of the nicest modern interiors in Batumi. A popular spot for brunches, slow breakfasts, evening drinks, and meeting friends.' where slug='nisha';
update guide_places set body=E'1905 \u2014 BatumiOne of Batumi\u2019s most atmospheric cocktail bars, inspired by classic European speakeasies. Dim lighting, vinyl music, jazz, and expertly crafted cocktails create a vibe that feels somewhere between Tbilisi, Berlin, and old Odessa.' where slug='1905-bar';
update guide_places set price=E'\u224810\u201340 \u20be' where slug='1905-bar';
update guide_places set body=E'Specialty Coffee Roastery & Shop\n\nOne of the best specialty coffee spots in Batumi for people who truly love coffee. They roast their own beans, serve excellent filter coffee and espresso, and the atmosphere feels more like a local European caf\u00e9 than a touristy place.\n\nPerfect for:\n\n* morning coffee\n* working with a laptop\n* a relaxed breakfast\n* buying beans to take home\n\n\U0001f4cd 8 Lermontov St\n\n09:00\u201322:00' where slug='kopi-brew';
update guide_places set body=E'A refined rooftop restaurant with 360\u00b0 views over the Old Town and the port, set poolside above the city. Expect a menu built around local seafood and smart vegetarian plates, plus a considered list of Georgian and international wines; cocktails are mixed at the rooftop bar. Open for dinner\u2014time it for sunset and linger for the skyline.\n\nBRE.GE CLUB recommends:\n\nGo classic\u2014order a seafood main and pair it with a glass of Georgian wine; or keep it lighter with a vegetarian plate and a cocktail from the bar. It\u2019s an easy, unhurried way to enjoy the view and the room\u2019s design\u2011forward vibe.\n\nWhere: Rooftop of Rooms Batumi' where slug='the-kitchen-by-rooms';
update guide_places set body=E'Daphna \u2014 khinkali & honest Georgian food in the heart of Batumi\n\nA city\u2011center spot for simple, satisfying Georgian classics without the fuss. Come for the cozy, casual vibe and stay for the dish this place is known for: handmade khinkali\u2014juicy, generously filled, and served piping hot. There\u2019s a short menu of comfort plates, local wine by the glass, and a smooth house chacha to match.\n\nBRE.GE CLUB recommends:\n\nOrder a full plate of classic khinkali (our pick here) and pair it with a shot of chacha\u2014or keep it light with a glass of local wine. It\u2019s the easiest way to taste why locals come back late after a seaside walk.\n\nGood to know: central location, friendly service, and late hours\u2014handy for an unplanned, no\u2011frills dinner after the boulevard.' where slug='daphna-batumi';
update guide_places set price=E'\u224820\u201370 \u20be' where slug='daphna-batumi';
update guide_places set body=E'The Ambassadori in Batumi is an absolute gem of a restaurant. It''s located in a really cool and scenic area, and has a cozy, elegant atmosphere with stunning views of the city from every angle.\n\nThis place is famous for their incredible Italian cuisine. Their chef uses only the best, freshest ingredients to create dishes that are to die for. From classic pasta and risotto to fresh salads and decadent meat dishes, there''s something for everyone.\n\nBut the creme brulee is a whole other level. It''s a work of art created with so much skill and attention to detail. The creamy custard, topped with a crunchy caramel crust, is just out of this world.\n\nAnd the wine list is equally impressive. You''ll find some of the finest Italian wines, as well as some gems from other countries. A knowledgeable sommelier can help you find the perfect wine to pair with your meal.The restaurant staff are all super friendly and really take care of you, making you feel right at home. The atmosphere is so cozy and welcoming, like you''re in a friend''s house. And the food is just incredible - you can''t go wrong. It''s not just about the food though, it''s also about the experience. Every time you go to the Ambassadori, it''s like a special occasion.' where slug='ambassadori-restaurant';
update guide_places set body=E'Cafe with some really good coffee from roasters in Saudi Arabia. It''s in the city center and they specialize in breakfast - you know, like Hokkaido toast or an English breakfast, or even some original dishes. And for coffee, they have a classic menu or you can try some different brewing methods.\n\nWe recommend the sweet Hokkaido toast with freshly made batch brew\n\nSpecial offer for the guests of the BRE apartments: show logo BRE.GE CLUB, get your coffee for free, when ordering any meal' where slug='urban-coffee';
update guide_places set body=E'The largest restaurant complex in Adjara with open kitchens one hundred meters above sea level opened in Batumi.\n\nPanorama is a multi-level restaurant complex by Ginza Project, an international company with twenty years of experience. A unique project with 360-degree view, dynamic terraces, and cuisine by the first Georgian chef recognized by the Michelin Guide.\n\nPanorama is located on four floors in the central ORBI Sea tower. Each level has its own atmosphere and is inspired by the multifaceted DNA of Georgian culture. With culinary accompaniment by Izo Dzandzava, you will feel like the most esteemed guest at a colorful and generous Georgian feast, whether you are with a hundred friends or on an intimate date for two. The menu features all the classics of Georgian cuisine \u2014 recipes passed down through generations in the Dzandzava family. But there is also room for creative interpretations, innovation, and gastronomic vision.\n\nThe Panorama restaurant complex is full of aesthetic and gastronomic experiences\u2014such a scale is presented in Batumi for the first time. Open kitchens, innovative technologies, a unique interpretation of Georgian cuisine, high-level service, and an incredible collection of rare Georgian wines. Perhaps here there is a complete absence of the casual charm of authentic tourist establishments, but it is this vision that the creators see as the future of Georgian restaurant culture' where slug='panorama-restaurant';
update guide_places set body=E'One of the coolest restaurants in town. They''ve got modern Georgian cuisine with a touch of Europe, and they go crazy for Asian food. It''s a really great place with awesome food. You could have a great night out there, and sometimes they even have live music. The chef''s even got a Michelin star!' where slug='g-garden-restaurant';
update guide_places set body=E'A restaurant in the heart of the city with authentic Georgian food. You can taste all the real Georgian flavors here: khachapuri, khinkali, ajapsandali, and more. The place often has live music and even has outdoor seating on the terrace.' where slug='tiflis';
update guide_places set price=E'\u224820\u201370 \u20be' where slug='tiflis';
update guide_places set body=E'This is a great cafe in the heart of the city that started as a little coffee shop. The staff are all experts in their field and they love coffee. You can get some amazing specialty coffee here, have lunch, drink some wine, and try some delicious desserts that they make themselves.' where slug='kava-lova';
update guide_places set price=E'\u224810\u201320 \u20be' where slug='kava-lova';
update guide_places set body=E'Pure is perhaps the most popular cafe in Batumi. Here, you can choose from a variety of ways to spend your time. Try the branded breakfasts, which are available until 7 p.m., and enjoy the excellent coffee, wine by the glass, and delicious salads and snacks.' where slug='pure-coffee';
update guide_places set price=E'\u224820\u201330 \u20be' where slug='pure-coffee';
update guide_places set body=E'JETJET is a modern electric scooter sharing service operating in Batumi through a mobile app with QR-based unlocking and flexible per-minute pricing. The service is especially convenient for short rides between caf\u00e9s, beaches, coworking spaces, and central areas of the city without needing taxis or rental cars.' where slug='jet-scooter-rent';
update guide_places set body=E'Taxi Maxim is a budget-friendly ride-hailing service operating in Batumi and other cities across Georgia. The app is especially popular among locals and long-term visitors thanks to lower prices compared to other taxi platforms and simple ride ordering process through the mobile app. taximaxim.com' where slug='maxim-taxi';
update guide_places set body=E'Yandex Go is one of the most widely used ride-hailing apps in Batumi for everyday transportation, airport rides, late-night trips, and moving around the city without needing a rental car. The service works through a mobile app with upfront pricing, live driver tracking, and multiple ride categories depending on comfort level and budget.\n\nThe app is especially popular for affordable rides between New Boulevard, Old Batumi, beaches, coworking spaces, restaurants, and nightlife areas. Users can pay by card or cash and order rides at almost any time of day, making it one of the most convenient transport options for both locals and tourists in Batumi.\n\nPerfect for:\n\n* airport transfers\n* affordable city rides\n* nightlife transportation\n* moving around Batumi without a car\n* everyday transportation\n\nWhat to expect:\n\n* app-based ride ordering\n* upfront pricing\n* card & cash payments\n* multiple ride categories\n* 24/7 availability\n\nAvailable across Batumi via mobile app\n\n24/7' where slug='yandex-go-taxi';
update guide_places set body=E'Bolt is the main ride-hailing service used in Batumi for everyday city transportation, airport trips, late-night rides, and moving around the city without needing a rental car. The app works similarly to Uber and is widely used both by locals and tourists thanks to its simple interface, fast pickup times, and affordable pricing.' where slug='bolt-taxi';
update guide_places set body=E'GetmancarA modern app-based carsharing service in Batumi designed for quick city trips, flexible daily rentals, and spontaneous travel around the city without paperwork or rental offices. Cars can be booked, unlocked, and managed directly through the Getmancar mobile app, making it one of the most convenient urban mobility options in Batumi.' where slug='getmancar-carsharing';
update guide_places set body=E'EasyRent Car RentalA modern car rental service in Batumi offering comfortable and flexible rental options for travelers exploring the city, the coastline, and mountain regions of Georgia. EasyRent is popular among tourists and digital nomads thanks to its easy booking process, well-maintained cars, and customer-oriented service.' where slug='easyrent-car-rental';
update guide_places set body=E'A local car rental service in Batumi offering practical and flexible rental options for travelers exploring the city, the coast, and mountain regions of Georgia. Especially convenient for visitors looking for simple rental conditions, affordable pricing, and easy communication without complicated booking process.\n\nThe service offers city cars, SUVs, and vehicles for longer trips around Georgia, with flexible rental conditions, unlimited mileage options, and no-deposit cars available for selected vehicles. Suitable both for short Batumi stays and long road trips across the country.\n\nPerfect for:\n\n* road trips around Georgia\n* mountain & coastal travel\n* affordable daily rentals\n* flexible rental conditions\n* independent travel around Batumi\n\nWhat to expect:\n\n* unlimited mileage\n* no-deposit car options\n* booking without prepayment\n* affordable pricing\n* local support\n\nCars from 80 GEL' where slug='vasily-car-rental';
update guide_places set body=E'Reliable car rental service in Batumi with a wide selection of cars, airport delivery, flexible pickup options and 24/7 support for traveling around Georgia. Open 24/7.\n\n90 Lermontov Str, Batumi\n\nOpen 24/7\n\nTags: Car Rental \u2022 Airport Delivery \u2022 Road Trips \u2022 New Boulevard \u2022 Travel Around Georgia\n\nA modern car rental service in Batumi popular among tourists, digital nomads, and travelers exploring Georgia by car. GeoDrive offers economy cars, SUVs, premium vehicles, airport delivery, one-way rentals between cities, and full support throughout the rental period.\n\nThe service works especially well for people planning road trips outside Batumi \u2014 to mountain regions, wineries, beaches, and smaller coastal towns. GeoDrive also provides flexible pickup and return options between Batumi, Tbilisi, Kutaisi, and airports across Georgia.\n\nPerfect for:\n\n* road trips around Georgia\n* airport pickup\n* long-term rental\n* mountain & coastal travel\n* flexible intercity travel\n\nWhat to expect:\n\n* insured vehicles\n* 24/7 support\n* airport delivery\n* one-way rental options\n* economy to premium cars\n\n220 Airport Highway, Batumi' where slug='geo-drive-car-rental';
update guide_places set body=E'Grand Bellagio Wellness & SPAA large modern wellness complex near New Boulevard with indoor pool, hammam, sauna, massage treatments, fitness facilities, and relaxing sea-view atmosphere. One of the biggest SPA spaces in Batumi for a full recovery and wellness day near the beach.' where slug='grand-bellagio-wellness-spa';
update guide_places set body=E'A modern premium wellness complex near New Boulevard combining indoor pool, Finnish sauna, hammam, massage treatments, fitness facilities, and a calm luxury atmosphere close to the sea. Orchid SPA is considered one of the most aesthetic and well-designed SPA spaces in Batumi, popular both among hotel guests and locals looking for a slower wellness-focused day.\n\nThe space combines soft modern interiors, large relaxation areas, wellness treatments, and a comfortable pool zone that works especially well during rainy weather, recovery days, or quiet evenings after the beach. The SPA also includes fitness facilities and different treatment programs focused on relaxation and recovery.\n\nPerfect for:\n\n* SPA & wellness\n* indoor pool\n* hammam & sauna\n* massage & recovery\n* wellness weekends near the sea\n\nWhat to try:\n\n* relaxing massage\n* hammam session\n* Finnish sauna\n* indoor pool access\n* wellness treatments & recovery programs\n\n5a Lech and Maria Kaczynski St, Batumi\n\nDaily: 08:00 \u2013 23:00' where slug='orchid-spa-batumi';
update guide_places set body=E'A modern luxury spa located inside Hilton Batumi, just steps from the boulevard and the sea. eforea SPA is one of the best-known wellness spaces in the city, combining indoor pool access, sauna, steam room, massages, fitness facilities, and relaxing treatments in a calm premium setting.\n\nThe spa is especially popular for recovery days, rainy weather, and slower wellness-focused weekends in Batumi. Treatments include classic massages, hot stone therapy, Vichy shower procedures, facials, and wellness rituals designed for full relaxation and reset' where slug='eforea-spa-at-hilton-batumi';
update guide_places set body=E'Shine SPA at Sheraton Batumi is one of the city\u2019s best-known luxury wellness spaces, combining classic hotel elegance with a full SPA & relaxation experience. The complex includes an indoor pool, jacuzzi, sauna, steam room, fitness facilities, and treatment rooms designed for slower recovery days and calm evenings near the boulevard.\n\nPerfect for:\n\n* SPA & wellness\n* indoor pool & jacuzzi\n* sauna & steam room\n* luxury relaxation\n* rainy day recovery\n\nWhat to try:\n\n* relaxing massage\n* jacuzzi & indoor pool\n* sauna & steam room\n* wellness treatments\n* spa evening after the beach\n\n28 Rustaveli Ave, Batumi\nDaily' where slug='sheraton-batumi-shine-spa';
update guide_places set body=E'A premium wellness space inside Radisson Blu Batumi combining panoramic sea views, modern SPA facilities, indoor pool, fitness center, and relaxing treatments in a calm luxury atmosphere. One of the best options in the city for a slower wellness day near the boulevard and Old Batumi.\n\nPerfect for:\n\n* SPA & wellness\n* indoor pool\n* sauna & steam room\n* relaxing massages\n* luxury slow living\n\nWhat to try:\n\n* Anne Semonin treatments\n* indoor pool access\n* sauna & steam room\n* relaxing massage\n* wellness day with sea views' where slug='radisson-blu-batumi-spa';
update guide_places set body=E'A large seaside wellness complex in New Boulevard with indoor and outdoor pools, sauna, steam room, massage treatments, gym, and direct beach access. One of the most popular SPA options in Batumi for a full relaxing day by the sea.\n\nThe hotel is especially known for its big indoor pool area, heated pool, outdoor seasonal pool, wellness zone, and panoramic sea views. Works well both for quick recovery days and full slow-living weekends near the beach.\n\nPerfect for:\n\n* SPA & wellness\n* indoor & outdoor pools\n* sauna & steam room\n* massage & recovery\n* seaside relaxation\n\nWhat to try:\n\n* indoor heated pool\n* sauna & steam room\n* relaxing massage\n* outdoor pool in summer\n* spa day with sea views\n\n18 Sherif Khimshiashvili St, Batumi\n\nDaily: 08:00 \u2013 22:00' where slug='colosseum-marina-spa';
update guide_places set body=E'A premium wellness and SPA space in the center of Old Batumi with indoor and outdoor pools, sauna, steam room, massages, fitness area, and panoramic sea views. One of the best options in the city for a slower luxury-style wellness day near the boulevard and the beach. The hotel\u2019s Explore Spa is especially known for its calm atmosphere, modern design, pool area, and massage treatments.\n\nPerfect for:\n\n* SPA & wellness\n* indoor pool\n* sauna & steam room\n* rainy day relaxation\n* luxury slow living\n\nWhat to try:\n\n* relaxing massage\n* sauna & steam room\n* indoor pool access\n* wellness treatments\n* spa day with sea views\n\nNinoshvili / Zhgenti Street, Batumi\n\nDaily: 07:00 \u2013 23:00' where slug='le-m-ridien-batumi-spa-wellness';
update guide_places set body=E'Gardenia Spa at STEPS BatumiA relaxed spa and wellness space located inside STEPS Batumi Hotel & Suites, close to New Boulevard and the sea. Gardenia Spa is a good option for a calm reset day without leaving the city \u2014 with massage, sauna, steam room, fitness facilities and pool access in one place.' where slug='gardenia-spa-at-steps-batumi';
update guide_places set body=E'D Block Workspace @ Rooms BatumiA stylish coworking and creative workspace located inside Rooms Batumi, combining modern design, comfortable work areas, fast Wi-Fi, and relaxed creative atmosphere in the heart of Old Batumi. D Block is especially popular among freelancers, designers, entrepreneurs, and remote workers looking for a more aesthetic and inspiring work environment near the sea.' where slug='d-block-workspace-rooms-batumi';
update guide_places set body=E'Terminal BatumiA modern coworking and creative workspace in the center of Batumi designed for freelancers, startups, remote workers, and digital nomads. Terminal combines comfortable work areas, fast Wi-Fi, meeting rooms, community atmosphere, and regular networking events in one of the city\u2019s most active professional spaces.' where slug='terminal-coworking';
update guide_places set body=E'A modern coworking space near New Boulevard and the sea, popular among freelancers, remote workers, startups, and digital nomads in Batumi. LendSpace combines a relaxed atmosphere, fast Wi-Fi, meeting rooms, quiet zones, and comfortable workspaces with a strong remote-work community vibe.\n\nThe space is especially convenient for people staying near the boulevard area who want a calm productive environment close to caf\u00e9s, restaurants, and the beach. LendSpace offers open-space desks, fixed workplaces, meeting rooms, tea & coffee, and comfortable common areas designed for long workdays and networking.\n\nPerfect for:\n\n* remote work\n* freelancers & startups\n* laptop-friendly workdays\n* networking & community\n* work near the sea\n\nWhat to expect:\n\n* fast Wi-Fi\n* meeting rooms\n* quiet zones\n* coffee & tea\n* flexible daily and monthly passes\n\n4 Sherif Khimshiashvili St, Batumi\n\nDaily: 10:00 \u2013 22:00' where slug='lendspace';